def max_difference(tuples):
    max_diff = 0
    for i in range(len(tuples)):
        a = tuples[i][0]
        for j in range(len(tuples)):
            if i != j:
                b = tuples[j][1]
                diff = a - b
                if diff > max_diff:
                    max_diff = diff
    return max_diff

assert max_difference([(3, 5), (1, 7), (10, 3), (1, 2)]) == 7
